<template>
  <table class="table">
    <thead>
      <tr>
        <th>
          <label class="form-checkbox">
            <th>Select All</th>
            <input
              type="checkbox"
              v-model="checkedB"
              @click="select"
              @change="$emit('update:listfilter', user.collection)"
              :style="{ width: '10px', height: '10px' }"
            />
            <i class="form-icon"></i>
          </label>
        </th>
      </tr>
    </thead>
    <tbody>
      <tr v-for="item in this.list" v-bind:key="item">
        <td>
          <label class="form-checkbox">
            <input
              type="checkbox"
              :value="item"
              @change="$emit('update:listfilter', user.collection)"
              v-model="user.collection"
              :style="{ width: '10px', height: '10px' }"
            />
            <i class="form-icon"></i>
          </label>
        </td>
        <td style="text-align: left">
          {{ item }}
        </td>
      </tr>
    </tbody>
  </table>
</template>

<script>
export default {
  name: "CheckFilters",
  props: {
    list: Array,
    listfilter: Array,
    tfCheck: Boolean,
  },
  data() {
    return {
      user: {
        collection: this.list,
      },
      checkedB: this.tfCheck,
    };
  },
  methods: {
    select() {
      this.user.collection = [];
      if (!this.checkedB) {
        for (let i in this.list) {
          this.user.collection.push(this.list[i]);
        }
      }
    },
  },
};
</script>

<style scoped>
.table {
  font-size: 0.8rem;
}
table {
  height: 250px;
}

tbody {
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
  align-content: space-around;
  justify-content: flex-start;
  align-items: stretch;
  padding-right: 1%;
}
tr {
  min-width: 150px;
}
th {
  padding-bottom: 10px;
}
</style>
