<template>
  <div id="corners">
    <v-style>
      .smooth-enter-to, .smooth-leave { height: {{ computedHeight }}; }
    </v-style>
    <button id="yo" v-on:click="toggleCollapse" value="show/hide">
      Toggle Filter
    </button>
    <tr id="yo2">
      <th>
        {{ this.filteredFinal.length }} of {{ this.inventory.length }} selected
      </th>
    </tr>
    <transition name="smooth">
      <div ref="myText" class="container1" v-show="show">
        <div id="support2">
          <div id="grp">
            <div v-for="option in this.options" :key="option">
              <div
                :class="option === selectCat ? 'active' : 'not-active'"
                v-on:click="
                  toggleCollapseOptions(option),
                    selected(option),
                    fRswap(option)
                "
              >
                {{ option }}
              </div>
            </div>
          </div>
          <!-- v-model  show-options  -->
          <CheckFilters
            :tfCheck="true"
            v-show="showOptions.support"
            :list="listOfSupports"
            :listfilter.sync="user.supportCollection"
          />
          <CheckFilters
            :tfCheck="true"
            v-show="showOptions.medium"
            :list="listOfMediums"
            :listfilter.sync="user.mediumCollection"
          />
          <CheckFilters
            :tfCheck="true"
            v-show="showOptions.series"
            :list="listOfSeries"
            :listfilter.sync="user.seriesCollection"
          />

          <!-- <CheckFilterssC
            :tfCheck="false"
            v-show="showOptions.red"
            :list="listOfReds"
            :filterValue.sync="user.filterValueR"
          />
          <CheckFilterssC
            :filterValue.sync="user.filterValueB"
            :tfCheck="false"
            v-show="showOptions.blue"
            :list="listOfBlues"
          />
          <CheckFilterssC
            :filterValue.sync="user.filterValueY"
            :tfCheck="false"
            v-show="showOptions.yellow"
            :list="listOfYellows"
          /> -->
        </div>
      </div>
    </transition>
    <!-- ///////////////////// -->
    <div class="container">
      <div class="gallery">
        <div
          class="sidebar"
          v-for="key in this.filteredFinal"
          :key="key.id"
          @click="logit(key)"
          v-on:click="isHidden = false"
        >
          <!-- {{ key.id}} -->
          <br />
          {{ key.id }}
          <ImageItem
            @click.native="highlight"
            styles="parent-styleGALLA"
            class="image__item"
            :source="require('@/assets/thumbnails/JPEG/' + key.id + '.jpg')"
            alt="random image"
          />
        </div>
      </div>
      <div id="frame">
        <div v-if="isHidden" id="contentsRight">
          Select an image to enlarge.
        </div>
        <div
          id="contentsRight"
          v-if="!isHidden"
          :style="{
            padding: '20px',
            'background-color': 'white',

            'margin-left': 'auto',
            'margin-right': 'auto',
          }"
        >
          <ImageItem
            @click.native="isHidden = !isHidden"
            styles="parent-style7"
            class="image__item"
            :source="require('@/assets/' + this.user.details1 + '.jpg')"
            alt="random image"
          />
          <div v-if="!isHidden" id="stickyDeets">
            {{ this.user.details1 }} | {{ this.user.details2 }} |
            {{ this.user.details3 }} | {{ this.user.details4 }} |
            {{ this.user.details5 }} | {{ this.user.details6 }} |
            {{ this.user.details7 }} | {{ this.user.details8 }} |
            {{ this.user.details9 }} |
          </div>
        </div>
      </div>
    </div>
    <!-- ///////////////////// -->
  </div>
</template>

<script>
// import * as d3 from "d3";

import CheckFilters from "./CheckFilterss.vue";
// import CheckFilterssC from "./CheckFilterssC.vue";
import ImageItem from "../ImageItem.vue";
export default {
  name: "testing",
  components: { CheckFilters, ImageItem },
  props: {
    inventory: Array,
    listOfSupports: Array,
    listOfMediums: Array,
    listOfSeries: Array,
    listOfReds: Array,
    listOfBlues: Array,
    listOfYellows: Array,
  },
  data() {
    return {
      inventory1: this.inventory,
      g: [],
      fR: "1",
      fB: "1",
      fY: "1",
      selectCat: "support",
      isActive: true,
      isHidden: true,
      theatrical: "",
      largerImg: "",
      show: false,
      options: [
        "support",
        "medium",
        "series",
        "red",
        "blue",
        "yellow",
        "monoChrome",
      ],
      showOptions: {
        support: true,
        medium: false,
        series: false,
        red: false,
        blue: false,
        yellow: false,
      },
      yoo: 1,
      computedHeight: "auto",
      user: {
        supportCollection: this.listOfSupports,
        mediumCollection: this.listOfMediums,
        seriesCollection: this.listOfSeries,
        // redCollection: this.listOfReds,
        // blueCollection: this.listOfBlues,
        // yellowCollection: this.listOfYellows,
        filterValueR: this.listOfReds,
        filterValueB: this.listOfBlues,
        filterValueY: this.listOfYellows,
        details1: "",
        details2: "",
        details3: "",
        details4: "",
        details5: "",
        details6: "",
        details7: "",
        details8: "",
        details9: "",
      },
    };
  },
  computed: {
    /////// main filter
    filteredFinal() {
      if (!this.inventory1) {
        return null;
      }
      let m = this.inventory1.filter(
        (d) =>
          d.imgname !== "99" &&
          d.imgname !== "98" &&
          this.user.supportCollection.includes(d.support) &&
          this.user.mediumCollection.includes(d.medium) &&
          this.user.seriesCollection.includes(d.series)

        //   &&
        //   d.red == this.fR) ||
        // d.blue == this.fB ||
        // d.yellow == this.fY
        // this.user.redCollection.includes(d.red) &&
        // this.user.blueCollection.includes(d.blue) &&
        // this.user.yellowCollection.includes(d.yellow)
      );
      // .filter((d) => this.user.redCollection.includes(d.red))
      // .filter((d) => this.user.blueCollection.includes(d.blue))
      // .filter((d) => this.user.yellowCollection.includes(d.yellow));
      return m.sort((a, b) => (a.year > b.year ? 1 : -1));
      // return m.sort((a, b) => (a.id > b.id ? 1 : -1));
    },

    preFilterR() {
      let m = this.filteredFinal.filter(
        (d) => d.imgname !== "99" && d.imgname !== "98" && d.red == this.fR
      );

      return m.sort((a, b) => (a.year > b.year ? 1 : -1));
    },
    preFilterB() {
      let m = this.filteredFinal.filter(
        (d) => d.imgname !== "99" && d.imgname !== "98" && d.blue == "1"
      );

      return m.sort((a, b) => (a.year > b.year ? 1 : -1));
    },
    preFilterY() {
      let m = this.filteredFinal.filter(
        (d) => d.imgname !== "99" && d.imgname !== "98" && d.yellow == "1"
      );

      return m.sort((a, b) => (a.year > b.year ? 1 : -1));
    },
    comboP() {
      let g = [];
      let b = this.preFilterR;
      let c = this.preFilterB;
      let d = this.preFilterY;
      let h = g.concat(b);
      let j = h.concat(c);
      let m = j.concat(d);
      return m;
    },
  },
  methods: {
    fRswap(option) {
      console.log(option);

      if (this.selectCat == "red") {
        this.inventory1 = this.inventory.filter(
          (d) =>
            d.red == "1" &&
            this.user.supportCollection.includes(d.support) &&
            this.user.mediumCollection.includes(d.medium) &&
            this.user.seriesCollection.includes(d.series)
        );
      } else if (this.selectCat == "blue") {
        this.inventory1 = this.inventory.filter(
          (d) =>
            d.blue == "1" &&
            this.user.supportCollection.includes(d.support) &&
            this.user.mediumCollection.includes(d.medium) &&
            this.user.seriesCollection.includes(d.series)
        );
      } else if (this.selectCat == "yellow") {
        this.inventory1 = this.inventory.filter(
          (d) =>
            d.yellow == "1" &&
            this.user.supportCollection.includes(d.support) &&
            this.user.mediumCollection.includes(d.medium) &&
            this.user.seriesCollection.includes(d.series)
        );
      } else if (this.selectCat == "monoChrome") {
        this.inventory1 = this.inventory.filter(
          (d) =>
            d.yellow == "1" ||
            d.red == "1" ||
            (d.blue == "1" &&
              this.user.supportCollection.includes(d.support) &&
              this.user.mediumCollection.includes(d.medium) &&
              this.user.seriesCollection.includes(d.series))
        );
      } else {
        this.inventory1 = this.inventory.filter(
          (d) =>
            d.red == "" ||
            (d.red == "1" &&
              this.user.supportCollection.includes(d.support) &&
              this.user.mediumCollection.includes(d.medium) &&
              this.user.seriesCollection.includes(d.series))
        );
      }

      console.log("hi");
    },
    selected(option) {
      this.selectCat = option;
    },
    handleSubmit() {
      alert(JSON.stringify(this.user));
    },
    removeHighlight() {
      this.theatrical = "";
    },
    toggleCollapse() {
      this.show = !this.show;
    },
    toggleCollapseOptions(option) {
      console.log(option + "hi");
      Object.keys(this.showOptions).forEach((key) => {
        this.showOptions[key] = false;
        console.log(key, this.showOptions[key]);
      });

      if (option == "support") {
        this.showOptions.support = !this.showOptions.support;
      }
      if (option == "medium") {
        this.showOptions.medium = !this.showOptions.medium;
      }
      if (option == "series") {
        this.showOptions.series = !this.showOptions.series;
      }
      if (option == "red") {
        this.showOptions.red = !this.showOptions.red;
      }
      if (option == "blue") {
        this.showOptions.blue = !this.showOptions.blue;
      }
      if (option == "yellow") {
        this.showOptions.yellow = !this.showOptions.yellow;
      }
      // this.showOptions.support = !this.showOptions.support;
      // this.showOptions.supportCollection == !this.showOptions.supportCollection;
    },
    initHeight() {
      this.$refs["myText"].style.position = "absolute";
      this.$refs["myText"].style.visibility = "hidden";
      this.$refs["myText"].style.display = "block";

      const height = getComputedStyle(this.$refs["myText"]).height;
      this.computedHeight = height;

      this.$refs["myText"].style.position = null;
      this.$refs["myText"].style.visibility = null;
      this.$refs["myText"].style.display = "none";
    },
    logit(key) {
      this.user.details1 = key.id;
      this.user.details2 = key.title;
      this.user.details3 = key.year;
      this.user.details4 = key.dimension;
      this.user.details5 = key.medium;
      this.user.details6 = key.support;
      this.user.details7 = key.series;
      this.user.details8 = key.gp;
      this.user.details9 = key.imgname;
    },
    highlight(event) {
      this.theatrical = event.target.src;

      console.log(event.target.src);
    },
  },
  mounted: function () {
    this.initHeight();
  },
};
</script>

<style scoped>
